middlewares.handlerTsCode:
(line: Message): Message | void => {
  const timestamp = line.json_content?.timestamp;
  if (typeof timestamp === "string") {
    const parsedTimestamp = Date.parse(timestamp);
    if (!Number.isNaN(parsedTimestamp)) {
      line.ts = parsedTimestamp;
      line.order_key = parsedTimestamp;
    }
  }

  // Logdy can assign the same internal id to several JSONL lines read in one batch.
  // Use the event timestamp and raw content so the browser does not collapse rows.
  if (typeof timestamp === "string") {
    line.id = `ora-${timestamp}-${line.content}`;
  }

  const correlationId = line.json_content?.trace_id || line.json_content?.request_id;
  if (typeof correlationId === "string" && correlationId.length > 0) {
    line.correlation_id = correlationId;
  }

  return line;
}
